--
-- Estructura para la vista `vw_calculo_mano_obra_ot`
--
DROP TABLE IF EXISTS `vw_calculo_mano_obra_ot`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_calculo_mano_obra_ot`  AS SELECT `wo`.`id_work_order` AS `id_work_order`, 'PRINCIPAL' AS `tipo`, `ip`.`id_instalador` AS `id_instalador`, `ip`.`nombre_instalador` AS `nombre_instalador`, `ip`.`valor_hora` AS `valor_hora`, `otj`.`fecha` AS `fecha`, `otj`.`hora_inicio` AS `hora_inicio`, `otj`.`hora_fin` AS `hora_fin` FROM ((`work_orders` `wo` join `orden_trabajo_jornadas` `otj` on(`otj`.`orden_trabajo_id` = `wo`.`id_work_order`)) join `instalador` `ip` on(`ip`.`id_instalador` = `wo`.`instalador_id`))union all select `otj`.`orden_trabajo_id` AS `id_work_order`,'ACOMPANANTE' AS `tipo`,`ia`.`id_instalador` AS `id_instalador`,`ia`.`nombre_instalador` AS `nombre_instalador`,`ia`.`valor_hora` AS `valor_hora`,`otj`.`fecha` AS `fecha`,`otj`.`hora_inicio` AS `hora_inicio`,`otj`.`hora_fin` AS `hora_fin` from (`orden_trabajo_jornadas` `otj` join `instalador` `ia` on(json_contains(`otj`.`acompanante_ot`,concat('[',`ia`.`id_instalador`,']'))))  ;

